import json
import logging
from functools import partial
from typing import Optional

from geosat.tools.urlprotocol import UrlReader, UrlProtocols

from psanp.pipeline import Pipeline
from psanp.server import PointCloudServer, process_cloud
from psanp.server.tcp import SocketFileIterator

logger = logging.getLogger(__name__)


def load_pipeline(pipeline_file: str) -> Pipeline:
    with UrlReader(pipeline_file, UrlProtocols()) as stream:
        pipeline_opts = json.load(stream)
    return Pipeline.from_options(pipeline_opts)


def start_server(
    pipeline_file: Optional[str] = None, host: str = "0.0.0.0", port: int = 5942
) -> None:
    """Start a TCP server that listens on the provided host and port, and that
    loads the provided pipeline file each time a point cloud is received.
    The pipeline is executed on the point cloud, which is then sent back to the client.

    :param pipeline_file: Path to the pipeline file. It is loaded each time a
        point cloud is received, which means the pipeline can be fine-tuned between
        two executions. If not provided, the server will send back the point cloud
        as-is. The client can set it later using the TCP protocol.
    :param host: Host to use for the server
    :param port: Port to listen on
    """
    if pipeline_file is not None:
        pipeline_loader = partial(load_pipeline, pipeline_file)
        cloud_callback = partial(process_cloud, pipeline_loader=pipeline_loader)
    else:
        cloud_callback = None
    file_iterator = SocketFileIterator(host, port)
    server = PointCloudServer(file_iterator, cloud_callback)
    server.start()
